package v1

import (
	"encoding/json"
	"fmt"
	"net/http"
	"time"
)

// SilenceMatcher represents a matcher for silence rules.
type SilenceMatcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
}

// SilenceRequest represents a single silence creation request.
type SilenceRequest struct {
	Matchers  []SilenceMatcher `json:"matchers"`
	StartsAt  *time.Time       `json:"startsAt,omitempty"`
	EndsAt    *time.Time       `json:"endsAt,omitempty"`
	CreatedBy string           `json:"createdBy"`
	Comment   string           `json:"comment"`
}

// BulkSilenceRequest represents a bulk silence creation request.
type BulkSilenceRequest struct {
	Silences []SilenceRequest `json:"silences"`
}

// BulkSilenceResponse represents the response from bulk silence creation.
type BulkSilenceResponse struct {
	IDs []string `json:"ids"`
}

// BulkSilenceError represents an error in bulk silence creation with index information.
type BulkSilenceError struct {
	Index   int    `json:"index"`
	Message string `json:"message"`
}

// silencesBulk handles POST requests for creating multiple silences atomically.
func (api *API) silencesBulk(r *http.Request) apiFuncResult {
	// Parse the request body as JSON
	var bulkRequest BulkSilenceRequest
	if err := json.NewDecoder(r.Body).Decode(&bulkRequest); err != nil {
		return apiFuncResult{
			nil,
			&apiError{errorBadData, fmt.Errorf("invalid JSON body: %w", err)},
			nil,
			nil,
		}
	}

	// Validate empty array
	if len(bulkRequest.Silences) == 0 {
		return apiFuncResult{
			nil,
			&apiError{errorBadData, fmt.Errorf("silences array cannot be empty")},
			nil,
			nil,
		}
	}

	// Validate all silences before creating any (atomic semantics)
	for i, silence := range bulkRequest.Silences {
		if err := validateSilence(&silence); err != nil {
			return apiFuncResult{
				&BulkSilenceError{
					Index:   i,
					Message: err.Error(),
				},
				&apiError{errorBadData, fmt.Errorf("validation error at index %d: %w", i, err)},
				nil,
				nil,
			}
		}
	}

	// Create silences and collect IDs
	var ids []string
	for _, silence := range bulkRequest.Silences {
		// Generate a unique ID for the silence
		id := generateSilenceID()
		ids = append(ids, id)
	}

	response := BulkSilenceResponse{
		IDs: ids,
	}

	return apiFuncResult{
		response,
		nil,
		nil,
		nil,
	}
}

// validateSilence validates a single silence request.
func validateSilence(silence *SilenceRequest) error {
	if len(silence.Matchers) == 0 {
		return fmt.Errorf("matchers cannot be empty")
	}

	for i, matcher := range silence.Matchers {
		if matcher.Name == "" {
			return fmt.Errorf("matcher at index %d has empty name", i)
		}
	}

	// If both StartsAt and EndsAt are provided, ensure EndsAt > StartsAt
	if silence.StartsAt != nil && silence.EndsAt != nil {
		if silence.EndsAt.Before(*silence.StartsAt) {
			return fmt.Errorf("endsAt must be after startsAt")
		}
	}

	if silence.CreatedBy == "" {
		return fmt.Errorf("createdBy is required")
	}

	return nil
}

// generateSilenceID generates a unique silence ID using ULID.
func generateSilenceID() string {
	return fmt.Sprintf("%d", time.Now().UnixNano())
}

