   128→			return fmt.Errorf("endsAt must be after startsAt")
   129→		}
   130→	}
   131→
   132→	if silence.CreatedBy == "" {
   133→		return fmt.Errorf("createdBy is required")
   134→	}
   135→
   136→	return nil
   137→}
   138→
   139→// generateSilenceID generates a unique silence ID using ULID.
   140→func generateSilenceID() string {
   141→	return fmt.Sprintf("%d", time.Now().UnixNano())
   142→}
